-- super-coder skills seed ΓÇö GENERATED by scripts/seed_skills.py.
-- System content: the catalogue propagates to every fork. Idempotent and
-- ID-STABLE: retires names no longer authored, then UPSERTs each skill by
-- name ΓÇö so skill_id never churns and shell_skills grants stay valid when
-- this re-runs as the update catalogue-sync. Do not hand-edit; author
-- assets/skills/<name>/SKILL.md then `./sc seed-skills`.

BEGIN;

-- Retire any catalogue skill that is no longer authored (soft-delete;
-- keeps the row + id so a re-add is stable and grants are recoverable).
UPDATE skills SET is_deleted=1 WHERE name NOT IN ('api-design', 'blueprint', 'bootstrap', 'cartographer', 'database-migrations', 'db_map', 'docs', 'flags', 'git', 'memory', 'onboard', 'self_update', 'snapshot', 'surface_catalogue');

INSERT INTO skills (name, description, category, command, common, content, is_deleted) VALUES (
  'api-design',
  'REST/HTTP API design patterns ΓÇö resource naming, status codes, pagination, filtering, errors, versioning, idempotency. Use when designing or reviewing API endpoints.',
  'craft',
  NULL,
  0,
  '# api-design ΓÇö designing & reviewing HTTP APIs

Catalogue skill (opt-in). Reach for it when shaping or reviewing an endpoint.

## Resources & methods
- Name resources as **plural nouns**, not verbs: `/users`, `/users/{id}/orders`.
- `GET` read (safe, idempotent) ┬╖ `POST` create / non-idempotent action ┬╖
  `PUT` full replace (idempotent) ┬╖ `PATCH` partial update ┬╖ `DELETE` remove.
- Nest only one level deep; beyond that, link by id.

## Status codes
- `200` ok ┬╖ `201` created (+ `Location`) ┬╖ `204` no content.
- `400` bad input ┬╖ `401` unauth ┬╖ `403` forbidden ┬╖ `404` not found ┬╖
  `409` conflict ┬╖ `422` validation ┬╖ `429` rate-limited.
- `5xx` = server''s fault; never use it for client errors.

## Payloads
- Consistent error shape: `{ "error": { "code", "message", "details" } }`.
- **Pagination**: cursor-based for large/changing sets (`?cursor=&limit=`),
  return `next_cursor`; offset only for small stable sets.
- **Filtering/sorting**: explicit query params (`?status=open&sort=-created`);
  whitelist fields ΓÇö never interpolate them into a query.
- Timestamps ISO-8601 UTC; ids opaque strings.

## Robustness
- **Idempotency**: make retries safe ΓÇö `PUT`/`DELETE` naturally; for `POST`,
  accept an idempotency key.
- **Versioning**: prefix (`/v1/ΓÇª`) or header; add fields backward-compatibly,
  never repurpose one.
- Validate at the boundary; reject unknown fields or ignore them ΓÇö decide and
  document. Don''t leak internals (stack traces, SQL) in errors.

## Review lens
Does each endpoint do one thing? Right method + status? Errors uniform? Inputs
validated/whitelisted? Retries safe? Breaking change hiding in a "small" tweak?',
  0
)
ON CONFLICT(name) DO UPDATE SET
  description=excluded.description, category=excluded.category,
